import React, { useEffect, useState } from "react";
import { auth, Namedb, provider } from "../components/firebase_setup";
import { signInWithPopup } from "firebase/auth";
import { useNavigate } from "react-router-dom";
import { collection, getDocs, query, where } from "firebase/firestore";

function SignIn() {
  const [Value, setValue] = useState("");
  const navigate = useNavigate();

  const handlesignIn = () => {
    signInWithPopup(auth, provider).then(async (data) => {
      const u_email = data.user.email;
      setValue(u_email);
      localStorage.setItem("email", u_email);
  
      // Query Firestore to check if the profile exists for the signed-in user
      const Pcol = collection(Namedb, "ProfileData");
      const profileQuery = query(Pcol, where("u_email", "==", u_email));
      const Pdata = await getDocs(profileQuery);
  
      if (!Pdata.empty) {
        // If profile exists, skip Home and go to Feed
        navigate("/feed");
      } else {
        // Otherwise, go to Home to set up profile
        navigate("/Home");
      }
    }).catch((error) => {
      console.error("Failed to sign in", error);
    });
  };

  useEffect(() => {
    const email = localStorage.getItem('email');
    if (email) {
      checkIfProfileExists(email);
    }
  }, []);

  const checkIfProfileExists = async (email) => {
    // Check if profile exists in Firestore for the user
    const Pcol = collection(Namedb, "ProfileData");
    const profileQuery = query(Pcol, where("u_email", "==", email));
    const Pdata = await getDocs(profileQuery);

    if (!Pdata.empty) {
      // If profile exists, skip Home and go to Feed
      navigate("/feed");
    }
  };

  return (
    <div className="signin_body">
      <h1 className="header">Welcome to Catsa. To continue Please use your Google account to log in.</h1>
      {Value ? (
        <button className="SigninButton" onClick={handlesignIn}>Continue to Home/Feed</button>
      ) : (
        <button className="SigninButton" onClick={handlesignIn}>Sign In With Google</button>
      )}
    </div>
  );
}

export default SignIn;
